#include <stdio.h>

// Function PROTOTYPE (declaration before main):
int add(int a, int b);
void greet(char *name);

int main() {
    printf("%d\n", add(5,3));  // 8
    greet("Neo");              // Hello, Neo!
    return 0;
}

// Function DEFINITION (after main):
int add(int a, int b) {
    return a + b;
}

void greet(char *name) {
    printf("Hello, %s!\n", name);
}

// Without prototype — define before use:
void printMsg() {
    printf("Hi!\n");
}
int main() {
    printMsg(); // OK — defined above
    return 0;
}

// WITH prototype — define anywhere:
int square(int n);  // prototype
int main() {
    printf("%d\n", square(4)); // compiles!
    return 0;
}
int square(int n) { return n*n; }

#include <stdio.h>

// Pass by VALUE — can't modify original:
void doubleVal(int x) {
    x *= 2;  // changes copy only
}

// Pass by POINTER — modifies original:
void doublePtr(int *x) {
    *x *= 2;  // dereference + modify
}

int main() {
    int n = 5;
    doubleVal(n);
    printf("%d\n", n);  // 5 — unchanged!

    doublePtr(&n);
    printf("%d\n", n);  // 10 — CHANGED!
    return 0;
}

void swap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

int x = 5, y = 10;
swap(&x, &y);
printf("%d %d\n", x, y); // 10 5
// Without pointers, swap is IMPOSSIBLE in C!

