#include <stdio.h>

int factorial(int n) {
    if (n <= 1) return 1;       // base case
    return n * factorial(n-1);  // recursive
}

int fib(int n) {
    if (n <= 1) return n;
    return fib(n-1) + fib(n-2);
}

int main() {
    printf("%d\n", factorial(5)); // 120
    printf("%d\n", fib(7));       // 13
    return 0;
}

// factorial(3) call stack:
// [main] calls factorial(3)
//   [factorial(3)] n=3, calls factorial(2)
//     [factorial(2)] n=2, calls factorial(1)
//       [factorial(1)] n=1, returns 1
//     [factorial(2)] gets 1, returns 2*1=2
//   [factorial(3)] gets 2, returns 3*2=6
// [main] gets 6

// Each frame has its OWN n!

#include <stdio.h>

void counter() {
    static int count = 0; // initialized ONCE
    count++;
    printf("%d\n", count);
}

int main() {
    counter(); // 1
    counter(); // 2
    counter(); // 3
    return 0;
}
// Without static, count resets to 0 each call!

